firmware_template.source:
#include "ltr390.h"
#include <Wire.h>
#include <Adafruit_LTR390.h>
static Adafruit_LTR390 ltr;
static float _uvi=0;static uint32_t _uv=0,_als=0;
static unsigned long _last=0;
void ltr390_setup(){Wire.begin();if(!ltr.begin()){Serial.println("[ltr390] Fail!");return;}ltr.setMode(LTR390_MODE_UVS);ltr.setGain(LTR390_GAIN_3);ltr.setResolution(LTR390_RESOLUTION_16BIT);Serial.println("[ltr390] OK");}
void ltr390_loop(){if(millis()-_last<1000)return;_last=millis();if(ltr.newDataAvailable()){_uv=ltr.readUVS();_uvi=ltr.getUVI();}}
float ltr390_get_uvi(){return _uvi;}
uint32_t ltr390_get_uv_raw(){return _uv;}
uint32_t ltr390_get_als(){return _als;}
